import{_ as e,o as d,c as o,ag as r}from"./chunks/framework.BBkp40gP.js";const h=JSON.parse('{"title":"Recipe IDs","description":"","frontmatter":{},"headers":[],"relativePath":"reference/recipe-ids.md","filePath":"reference/recipe-ids.md"}'),a={name:"reference/recipe-ids.md"};function c(i,t,s,n,l,g){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="recipe-ids" tabindex="-1">Recipe IDs <a class="header-anchor" href="#recipe-ids" aria-label="Permalink to &quot;Recipe IDs&quot;">​</a></h1><p>Complete list of recipe IDs generated by Nostalgic Trees. Use these with <code>event.remove({ id: ... })</code> in KubeJS scripts.</p><h2 id="recipe-type-ids" tabindex="-1">Recipe type IDs <a class="header-anchor" href="#recipe-type-ids" aria-label="Permalink to &quot;Recipe type IDs&quot;">​</a></h2><p>Used with <code>event.remove({ type: ... })</code> to target all recipes of a type, or with <code>event.custom({ type: ... })</code> to add new ones.</p><table tabindex="0"><thead><tr><th>Type ID</th><th>Purpose</th></tr></thead><tbody><tr><td><code>nostalgictrees:mutation</code></td><td>Sapling mutation via bee pollination</td></tr><tr><td><code>nostalgictrees:drying</code></td><td>Drying rack transformations</td></tr></tbody></table><p>All other NT recipes use vanilla types: <code>minecraft:crafting_shaped</code>, <code>minecraft:crafting_shapeless</code>, <code>minecraft:smelting</code>, <code>minecraft:smithing_transform</code>.</p><h2 id="per-tree-recipe-ids" tabindex="-1">Per-tree recipe IDs <a class="header-anchor" href="#per-tree-recipe-ids" aria-label="Permalink to &quot;Per-tree recipe IDs&quot;">​</a></h2><p>For every tree in <code>config/nostalgictrees/trees/</code>, two recipes are generated. Replace <code>&lt;tree&gt;</code> with the tree&#39;s <code>name</code> value (<code>iron</code>, <code>diamond</code>, <code>copper</code>, etc.).</p><table tabindex="0"><thead><tr><th>ID pattern</th><th>Type</th><th>What it does</th></tr></thead><tbody><tr><td><code>nostalgictrees:&lt;tree&gt;_chunk</code></td><td><code>crafting_shapeless</code></td><td>Stripped log → chunk</td></tr><tr><td><code>nostalgictrees:&lt;tree&gt;_resource</code></td><td><code>crafting_shaped</code></td><td>4 apples + 4 chunks + 1 honeycomb → tree&#39;s output item</td></tr></tbody></table><h2 id="mutation-recipe-ids" tabindex="-1">Mutation recipe IDs <a class="header-anchor" href="#mutation-recipe-ids" aria-label="Permalink to &quot;Mutation recipe IDs&quot;">​</a></h2><p>One per tier 2+ tree that has a mutation recipe. Pattern: <code>nostalgictrees:&lt;resulttree&gt;_mutation</code>.</p><table tabindex="0"><thead><tr><th>ID</th><th>Produces</th></tr></thead><tbody><tr><td><code>nostalgictrees:copper_mutation</code></td><td>copper sapling</td></tr><tr><td><code>nostalgictrees:iron_mutation</code></td><td>iron sapling</td></tr><tr><td><code>nostalgictrees:redstone_mutation</code></td><td>redstone sapling</td></tr><tr><td><code>nostalgictrees:amethyst_mutation</code></td><td>amethyst sapling</td></tr><tr><td><code>nostalgictrees:prismarine_mutation</code></td><td>prismarine sapling</td></tr><tr><td><code>nostalgictrees:experience_mutation</code></td><td>experience sapling</td></tr><tr><td><code>nostalgictrees:quartz_mutation</code></td><td>quartz sapling</td></tr><tr><td><code>nostalgictrees:gold_mutation</code></td><td>gold sapling</td></tr><tr><td><code>nostalgictrees:lapis_mutation</code></td><td>lapis sapling</td></tr><tr><td><code>nostalgictrees:glowstone_mutation</code></td><td>glowstone sapling</td></tr><tr><td><code>nostalgictrees:diamond_mutation</code></td><td>diamond sapling</td></tr><tr><td><code>nostalgictrees:emerald_mutation</code></td><td>emerald sapling</td></tr><tr><td><code>nostalgictrees:obsidian_mutation</code></td><td>obsidian sapling</td></tr><tr><td><code>nostalgictrees:netherite_mutation</code></td><td>netherite sapling</td></tr></tbody></table><h2 id="drying-recipe-ids" tabindex="-1">Drying recipe IDs <a class="header-anchor" href="#drying-recipe-ids" aria-label="Permalink to &quot;Drying recipe IDs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Transforms</th></tr></thead><tbody><tr><td><code>nostalgictrees:dirt_to_stone_sapling</code></td><td>dirt sapling → stone sapling</td></tr><tr><td><code>nostalgictrees:clay_ball_to_bone_meal</code></td><td>clay ball → bone meal</td></tr><tr><td><code>nostalgictrees:bone_block_to_snow_block</code></td><td>bone block → snow block</td></tr></tbody></table><h2 id="sapling-crafting-ids-tier-1" tabindex="-1">Sapling crafting IDs (tier 1) <a class="header-anchor" href="#sapling-crafting-ids-tier-1" aria-label="Permalink to &quot;Sapling crafting IDs (tier 1)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Produces</th></tr></thead><tbody><tr><td><code>nostalgictrees:dirt_sapling</code></td><td>dirt sapling</td></tr><tr><td><code>nostalgictrees:gravel_sapling_from_smelting</code></td><td>gravel sapling</td></tr><tr><td><code>nostalgictrees:sand_sapling_from_smelting</code></td><td>sand sapling</td></tr><tr><td><code>nostalgictrees:clay_sapling</code></td><td>clay sapling</td></tr><tr><td><code>nostalgictrees:bone_sapling</code></td><td>bone sapling</td></tr><tr><td><code>nostalgictrees:coal_sapling</code></td><td>coal sapling</td></tr><tr><td><code>nostalgictrees:ice_sapling</code></td><td>ice sapling</td></tr><tr><td><code>nostalgictrees:rgb_sapling</code></td><td>rgb sapling</td></tr></tbody></table><h2 id="mallet-crafting-ids" tabindex="-1">Mallet crafting IDs <a class="header-anchor" href="#mallet-crafting-ids" aria-label="Permalink to &quot;Mallet crafting IDs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Produces</th><th>Type</th></tr></thead><tbody><tr><td><code>nostalgictrees:wooden_mallet</code></td><td>wooden mallet</td><td>shaped</td></tr><tr><td><code>nostalgictrees:stone_mallet</code></td><td>stone mallet</td><td>shaped</td></tr><tr><td><code>nostalgictrees:iron_mallet</code></td><td>iron mallet</td><td>shaped</td></tr><tr><td><code>nostalgictrees:golden_mallet</code></td><td>golden mallet</td><td>shaped</td></tr><tr><td><code>nostalgictrees:diamond_mallet</code></td><td>diamond mallet</td><td>shaped</td></tr><tr><td><code>nostalgictrees:netherite_mallet</code></td><td>netherite mallet</td><td>smithing</td></tr></tbody></table><h2 id="block-crafting-ids" tabindex="-1">Block crafting IDs <a class="header-anchor" href="#block-crafting-ids" aria-label="Permalink to &quot;Block crafting IDs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Produces</th></tr></thead><tbody><tr><td><code>nostalgictrees:advanced_beehive</code></td><td>advanced beehive</td></tr><tr><td><code>nostalgictrees:drying_rack</code></td><td>drying rack</td></tr></tbody></table><h2 id="rgb-dye-conversion-ids" tabindex="-1">RGB dye conversion IDs <a class="header-anchor" href="#rgb-dye-conversion-ids" aria-label="Permalink to &quot;RGB dye conversion IDs&quot;">​</a></h2><p>One recipe per vanilla dye color. Pattern: <code>nostalgictrees:rgb_dye_to_&lt;color&gt;</code>.</p><table tabindex="0"><thead><tr><th>ID pattern</th><th>Example</th></tr></thead><tbody><tr><td><code>nostalgictrees:rgb_dye_to_&lt;color&gt;</code></td><td><code>nostalgictrees:rgb_dye_to_white</code>, <code>nostalgictrees:rgb_dye_to_orange</code>, etc.</td></tr></tbody></table><p>Where <code>&lt;color&gt;</code> is any of: <code>white</code>, <code>orange</code>, <code>magenta</code>, <code>light_blue</code>, <code>yellow</code>, <code>lime</code>, <code>pink</code>, <code>gray</code>, <code>light_gray</code>, <code>cyan</code>, <code>purple</code>, <code>blue</code>, <code>brown</code>, <code>green</code>, <code>red</code>, <code>black</code>.</p><h2 id="discovering-ids-yourself" tabindex="-1">Discovering IDs yourself <a class="header-anchor" href="#discovering-ids-yourself" aria-label="Permalink to &quot;Discovering IDs yourself&quot;">​</a></h2><p>If something isn&#39;t listed here (new trees, unreleased features), dump the registry:</p><ol><li>In-game, run <code>/kubejs dump</code></li><li>Open <code>kubejs/exported/recipes.txt</code></li><li>Search for <code>nostalgictrees:</code> — every NT recipe ID is there</li></ol><p>This is also the fastest way to confirm your <code>event.remove</code> target actually exists. A typo in the ID means <code>event.remove</code> silently does nothing — checking the dump first saves confusion.</p>',28)])])}const m=e(a,[["render",c]]);export{h as __pageData,m as default};
